import { useState, useEffect, useCallback } from 'react';
import { notificationAPI } from '../services/api';
import './Notifications.css';

// ─── Type → icon / badge class mapping ───────────────────────────────────────

const TYPE_META = {
  ORDER_PLACED:     { icon: '🛒', iconClass: 'order',   badgeClass: 'order-placed',     label: 'Order Placed'    },
  ORDER_CONFIRMED:  { icon: '✅', iconClass: 'order',   badgeClass: 'order-placed',     label: 'Confirmed'       },
  ORDER_DISPATCHED: { icon: '🚚', iconClass: 'order',   badgeClass: 'order-dispatched', label: 'Dispatched'      },
  ORDER_DELIVERED:  { icon: '📦', iconClass: 'order',   badgeClass: 'order-delivered',  label: 'Delivered'       },
  ORDER_CANCELLED:  { icon: '❌', iconClass: 'order',   badgeClass: 'order-cancelled',  label: 'Cancelled'       },
  PAYMENT_SUCCESS:  { icon: '💳', iconClass: 'payment', badgeClass: 'payment-success',  label: 'Payment Success' },
  PAYMENT_FAILED:   { icon: '⚠️', iconClass: 'payment', badgeClass: 'payment-failed',   label: 'Payment Failed'  },
  LOW_STOCK:        { icon: '📉', iconClass: 'admin',   badgeClass: 'low-stock',        label: 'Low Stock'       },
  NEW_ORDER:        { icon: '🔔', iconClass: 'admin',   badgeClass: 'new-order',        label: 'New Order'       },
  GENERAL:          { icon: '💬', iconClass: 'general', badgeClass: 'general',          label: 'General'         },
};

const getMeta = (type) =>
  TYPE_META[type] || { icon: '🔔', iconClass: 'general', badgeClass: 'general', label: type };

// ─── Time formatter ───────────────────────────────────────────────────────────

const formatTime = (createdAt) => {
  if (!createdAt) return '';
  const date = new Date(createdAt);
  const now  = new Date();
  const diff = Math.floor((now - date) / 1000); // seconds

  if (diff < 60)        return 'Just now';
  if (diff < 3600)      return `${Math.floor(diff / 60)}m ago`;
  if (diff < 86400)     return `${Math.floor(diff / 3600)}h ago`;
  if (diff < 86400 * 7) return `${Math.floor(diff / 86400)}d ago`;
  return date.toLocaleDateString('en-IN', { day: 'numeric', month: 'short', year: 'numeric' });
};

// ─── Filter options ───────────────────────────────────────────────────────────

const FILTER_OPTIONS = [
  { label: 'All',      value: 'ALL'      },
  { label: 'Unread',   value: 'UNREAD'   },
  { label: 'Orders',   value: 'ORDERS'   },
  { label: 'Payments', value: 'PAYMENTS' },
];

const matchesFilter = (n, filter) => {
  if (filter === 'ALL')      return true;
  if (filter === 'UNREAD')   return !n.isRead;
  if (filter === 'ORDERS')   return n.type.startsWith('ORDER_');
  if (filter === 'PAYMENTS') return n.type.startsWith('PAYMENT_');
  return true;
};

// ─── Component ────────────────────────────────────────────────────────────────

export default function Notifications() {
  const [notifications, setNotifications] = useState([]);
  const [unreadCount,   setUnreadCount]   = useState(0);
  const [filter,        setFilter]        = useState('ALL');
  const [loading,       setLoading]       = useState(true);
  const [error,         setError]         = useState('');
  const [actionLoading, setActionLoading] = useState(null);

  // ── Fetch ───────────────────────────────────────────────────────────────────

  const fetchNotifications = useCallback(async () => {
    setLoading(true);
    setError('');
    try {
      const [notifRes, countRes] = await Promise.all([
        notificationAPI.getMyNotifications(),
        notificationAPI.getUnreadCount(),
      ]);
      setNotifications(notifRes.data || []);
      setUnreadCount(countRes.data?.unreadCount ?? 0);
    } catch (err) {
      setError('Failed to load notifications. Please try again.');
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => {
    fetchNotifications();
  }, [fetchNotifications]);

  // ── Mark single as read ──────────────────────────────────────────────────────

  const handleMarkRead = async (id) => {
    setActionLoading(id);
    try {
      await notificationAPI.markAsRead(id);
      setNotifications(prev =>
        prev.map(n => n.notificationId === id ? { ...n, isRead: true } : n)
      );
      setUnreadCount(prev => Math.max(0, prev - 1));
    } catch {
      setError('Could not mark notification as read.');
    } finally {
      setActionLoading(null);
    }
  };

  // ── Mark all as read ─────────────────────────────────────────────────────────

  const handleMarkAllRead = async () => {
    try {
      await notificationAPI.markAllRead();
      setNotifications(prev => prev.map(n => ({ ...n, isRead: true })));
      setUnreadCount(0);
    } catch {
      setError('Could not mark all notifications as read.');
    }
  };

  // ── Delete ────────────────────────────────────────────────────────────────────

  const handleDelete = async (id) => {
    setActionLoading(id);
    try {
      await notificationAPI.deleteNotification(id);
      const deleted = notifications.find(n => n.notificationId === id);
      setNotifications(prev => prev.filter(n => n.notificationId !== id));
      if (deleted && !deleted.isRead) {
        setUnreadCount(prev => Math.max(0, prev - 1));
      }
    } catch {
      setError('Could not delete notification.');
    } finally {
      setActionLoading(null);
    }
  };

  // ── Filtered list ─────────────────────────────────────────────────────────────

  const filtered = notifications.filter(n => matchesFilter(n, filter));

  // ── Render ────────────────────────────────────────────────────────────────────

  return (
    <div className="notifications-page">
      <div className="notifications-container">

        {/* Header */}
        <div className="notifications-header">
          <h1>
            🔔 Notifications
            {unreadCount > 0 && (
              <span className="badge">{unreadCount}</span>
            )}
          </h1>
          {unreadCount > 0 && (
            <button className="mark-all-btn" onClick={handleMarkAllRead}>
              Mark all as read
            </button>
          )}
        </div>

        {/* Error */}
        {error && <div className="notif-error">{error}</div>}

        {/* Filter Tabs */}
        <div className="filter-tabs">
          {FILTER_OPTIONS.map(opt => (
            <button
              key={opt.value}
              className={`filter-tab${filter === opt.value ? ' active' : ''}`}
              onClick={() => setFilter(opt.value)}
            >
              {opt.label}
            </button>
          ))}
        </div>

        {/* Loading */}
        {loading && (
          <div className="notif-loading">Loading notifications…</div>
        )}

        {/* Empty */}
        {!loading && filtered.length === 0 && (
          <div className="notif-empty">
            <div className="notif-empty-icon">🔕</div>
            <h3>No notifications here</h3>
            <p>
              {filter === 'UNREAD'
                ? "You're all caught up! No unread notifications."
                : 'Nothing to show for this filter yet.'}
            </p>
          </div>
        )}

        {/* Notification Cards */}
        {!loading && filtered.map(n => {
          const meta       = getMeta(n.type);
          const isActioning = actionLoading === n.notificationId;

          return (
            <div
              key={n.notificationId}
              className={`notification-card${!n.isRead ? ' unread' : ''}`}
            >
              {/* Icon */}
              <div className={`notif-icon ${meta.iconClass}`}>
                {meta.icon}
              </div>

              {/* Content */}
              <div className="notif-content">
                <div className="notif-message">{n.message}</div>
                <div className="notif-meta">
                  <span className={`notif-type-badge ${meta.badgeClass}`}>
                    {meta.label}
                  </span>
                  <span className="notif-time">
                    {formatTime(n.createdAt)}
                  </span>
                </div>
              </div>

              {/* Unread dot */}
              {!n.isRead && <div className="unread-dot" />}

              {/* Actions */}
              <div className="notif-actions">
                {!n.isRead && (
                  <button
                    className="notif-action-btn"
                    title="Mark as read"
                    disabled={isActioning}
                    onClick={() => handleMarkRead(n.notificationId)}
                  >
                    ✓
                  </button>
                )}
                <button
                  className="notif-action-btn delete"
                  title="Delete"
                  disabled={isActioning}
                  onClick={() => handleDelete(n.notificationId)}
                >
                  🗑
                </button>
              </div>
            </div>
          );
        })}

      </div>
    </div>
  );
}
